#usda 1.0
(
    defaultPrim = "Shot"
    subLayers = [
        @/private/var/folders/k0/jp_x85zj55nf3ssm76z3dmmh0000gn/T/llm-bench-5im35vcn/assets.usda@
    ]
)

def Xform "Shot"
{
    def Xform "Set"
    {
        def Xform "ChairA" (
            prepend references = @/private/var/folders/k0/jp_x85zj55nf3ssm76z3dmmh0000gn/T/llm-bench-5im35vcn/assets.usda@</Assets/Chair>
        )
        {
            double3 xformOp:translate = (-2, 0, 0)
            uniform token[] xformOpOrder = ["xformOp:translate"]
        }

        def Xform "ChairB" (
            prepend references = @/private/var/folders/k0/jp_x85zj55nf3ssm76z3dmmh0000gn/T/llm-bench-5im35vcn/assets.usda@</Assets/Chair>
        )
        {
            double3 xformOp:translate = (2, 0, 0)
            uniform token[] xformOpOrder = ["xformOp:translate"]
        }
    }

    def Xform "Lighting" (
        variants = {
            string lightingVariant = "day"
        }
        prepend variantSets = "lightingVariant"
    )
    {
        variantSet "lightingVariant" = {
            "day" {
                def DistantLight "Sun"
                {
                    float inputs:intensity = 50000
                }

            }
            "night" {
                def DomeLight "Sky"
                {
                    float inputs:intensity = 500
                }

            }
        }
    }
}
